# Auto-generates Markdown documentation for all auto-generated methods
$methodFiles = Get-ChildItem -Path "D:/lazy init ide/auto_generated_methods" -Filter "*_AutoMethod.ps1"
$docPath = "D:/lazy init ide/auto_generated_methods/AutoGeneratedMethods_Documentation.md"
$docs = @()
$docs += "# Auto-Generated Methods Documentation\n"
foreach ($file in $methodFiles) {
    $lines = Get-Content $file.FullName
    $funcLine = $lines | Where-Object { $_ -match '^function ' }
    $funcName = ($funcLine -split ' ')[1]
    $docs += "## $funcName\n"
    $docs += "- **Source File:** $($file.BaseName -replace '_AutoMethod$','')"
    $docs += "- **Generated:** $(Get-Date -Format o)"
    $docs += "- **Purpose:** Auto-generated stub for manifest reverse engineering.\n"
    $docs += '```powershell'
    $docs += ($lines -join "\n")
    $docs += '```\n'
}
$docs -join "\n" | Set-Content $docPath
Write-Host "[AutoDocs] Documentation generated at $docPath"